  if (event.data === "right_mouse_button_clicked") {
    // Handle the message received
    console.log("Right mouse button clicked in the child window.");
  }
});

function sendRightClickMessage() {
  // Find the child window or iframe
  var childWindow = document.getElementById("childWindow").contentWindow;

  // Send the message
  childWindow.postMessage("right_mouse_button_clicked", "*");
}
```

