using System;
using System.Runtime.InteropServices;
using System.Windows.Forms;

[DllImport("user32.dll")]
public static extern IntPtr WindowFromPoint(Point point);

[DllImport("user32.dll", CharSet = CharSet.Auto)]
public static extern bool PostMessage(IntPtr hWnd, uint Msg, IntPtr wParam, IntPtr lParam);

const uint WM_RBUTTONDOWN = 0x0204;
const uint WM_RBUTTONUP = 0x0205;

static void SendRightMouseClickToProcess(Process targetProcess)
{
    IntPtr targetWindowHandle = targetProcess.MainWindowHandle;

    // Get the current cursor position
    Point cursorPosition = Cursor.Position;

    // Find the window at the cursor position
    IntPtr windowHandleAtCursor = WindowFromPoint(cursorPosition);

    if (windowHandleAtCursor == targetWindowHandle)
    {
        // Convert the cursor position to the client coordinates of the window
        ScreenToClient(targetWindowHandle, ref cursorPosition);

        // Send the right mouse button down event at the cursor position
        PostMessage(targetWindowHandle, WM_RBUTTONDOWN, IntPtr.Zero,
            (IntPtr)((cursorPosition.Y << 16) | cursorPosition.X));

        // Send the right mouse button up event at the cursor position
        PostMessage(targetWindowHandle, WM_RBUTTONUP, IntPtr.Zero,
            (IntPtr)((cursorPosition.Y << 16) | cursorPosition.X));
    }
}
```

